errors = True
while errors:
    errors = False
    for i, (x_i, t_i) in enumerate(zip(X, t)):
        corr_t_i = 1 if t_i else -1
        ext_x = np.concatenate([np.ones(1), x_i.flatten()])
        if np.sign(w.dot(ext_x)) != corr_t_i:
            errors = True
        w = w + ext_x * corr_t_i
